import React, { useCallback, useEffect, useMemo, useState } from 'react';
import { FormMode, isEditingMode } from '../form/FormMode';
import { useViewMobileLayout, useDeviceContentSize } from '@linm-soft-org/linm-web-common-components';
import { ToolbarResponsiveRow } from './ToolbarResponsiveRow';
import type { ToolbarOverflowItem } from './ToolbarOverflowMenu';
import { VoucherPagerNav } from './VoucherPagerNav';
import styles from './VoucherFormToolbar.module.css';
import type { VoucherToolbarDisabledReasons, VoucherViewModeHint } from './voucherToolbarTypes';

export type { VoucherToolbarDisabledReasons, VoucherViewModeHint } from './voucherToolbarTypes';

/** @deprecated Use FormMode from `components/form` */
export type VoucherFormMode = FormMode;

function toolbarButtonTitle(enabled: boolean, enabledTitle: string, disabledReason?: string): string {
  if (!enabled && disabledReason?.trim()) return disabledReason.trim();
  return enabledTitle;
}

export interface VoucherFormToolbarProps {
  testIdPrefix: string;
  title: string;
  /** Pill Mức xử lý — `VoucherFormStatusGroup`. Cấm badge `status` / `VoucherStatusBadge`. */
  processingLevelBadge?: React.ReactNode;
  formMode: FormMode;
  /** Hint một dòng dưới title — `resolveVoucherViewModeHint`. */
  viewModeHint?: VoucherViewModeHint | null;
  canApprove?: boolean;
  /** false — không render nút Phê duyệt (thiếu quyền). Default: true trong view mode. */
  showApproveButton?: boolean;
  canPost?: boolean;
  /** false — không render nút Ghi sổ (mức xử lý 9). */
  showPostButton?: boolean;
  canCopy?: boolean;
  canPrint?: boolean;
  canHistory?: boolean;
  canEdit?: boolean;
  canDelete?: boolean;
  /** false — disable nút Lưu (thiếu quyền create/update). Default true. */
  canSave?: boolean;
  /** false — ẩn nút Sửa (rule: đã phê duyệt / không Draft). Default true. */
  showEditButton?: boolean;
  /** false — ẩn nút Xóa. Default true. */
  showDeleteButton?: boolean;
  /** false — ẩn nút Tạo mới (view/detail). Default true. */
  showNewButton?: boolean;
  saving?: boolean;
  posting?: boolean;
  saveLabel?: string;
  searchNav?: {
    index: number;
    total: number;
    onFirst: () => void;
    onPrev: () => void;
    onNext: () => void;
    onEnd: () => void;
  };
  onBack: () => void;
  onApprove: () => void;
  onPost: () => void;
  onCopy: () => void;
  onPrint: () => void;
  onHistory?: () => void;
  onSearch: () => void;
  onNew: () => void;
  onEdit: () => void;
  onSave: () => void;
  onCancel: () => void;
  onDelete: () => void;
  /** Lý do disable — hiển thị qua `title` khi hover (rule `voucher-form-toolbar.md`). */
  disabledReasons?: VoucherToolbarDisabledReasons;
  /** Padding/card đồng bộ `pageFormHeader` / footer inset (voucher full-page). */
  insetShell?: boolean;
  /** Số CT nguồn sau Copy — hint «Bạn đang thực hiện copy từ …». */
  copySourceVoucherCode?: string | null;
  /** Hiển thị nút Xem sổ cái (dữ liệu đã post). */
  canViewLedger?: boolean;
  onViewLedger?: () => void;
  canViewLinkedVoucher?: boolean;
  onViewLinkedVoucher?: () => void;
  viewLinkedVoucherLabel?: string;
}

const DETAIL_ACTIONS_MAX_VISIBLE = 3;

export const VoucherFormToolbar: React.FC<VoucherFormToolbarProps> = ({
  testIdPrefix,
  title,
  processingLevelBadge,
  formMode,
  viewModeHint,
  canApprove = false,
  showApproveButton = true,
  canPost = false,
  showPostButton = true,
  canCopy = false,
  canPrint = false,
  canHistory = false,
  canEdit = false,
  canDelete = false,
  canSave = true,
  showEditButton = true,
  showDeleteButton = true,
  showNewButton = true,
  saving = false,
  posting = false,
  saveLabel = 'Lưu',
  searchNav,
  onBack,
  onApprove,
  onPost,
  onCopy,
  onPrint,
  onHistory,
  onSearch,
  onNew,
  onEdit,
  onSave,
  onCancel,
  onDelete,
  disabledReasons,
  insetShell = false,
  copySourceVoucherCode,
  canViewLedger = false,
  onViewLedger,
  canViewLinkedVoucher = false,
  onViewLinkedVoucher,
  viewLinkedVoucherLabel = 'Xem hóa đơn',
}) => {
  const tid = (s: string) => `${testIdPrefix}-toolbar-${s}`;
  const isEditing = isEditingMode(formMode);
  const isViewMode = formMode === FormMode.View;
  const viewMobile = useViewMobileLayout();
  const { isSmall: contentSmall } = useDeviceContentSize();
  const hasNav = !isEditing && searchNav && searchNav.total > 0;
  const [mobileToolbarExpanded, setMobileToolbarExpanded] = useState(false);
  /** Touch + content small + View — collapsed toolbar: Quay lại + nav + icon ⌄. */
  const useCompactToolbar = viewMobile && contentSmall && isViewMode;

  useEffect(() => {
    if (!useCompactToolbar) {
      setMobileToolbarExpanded(false);
    }
  }, [useCompactToolbar]);

  const showMobileCollapsed = useCompactToolbar && !mobileToolbarExpanded;
  const showMobileExpanded = viewMobile && isViewMode && !showMobileCollapsed;

  const renderSearchNav = useCallback(() => {
    if (!hasNav || !searchNav) return null;
    return (
      <VoucherPagerNav
        index={searchNav.index}
        total={searchNav.total}
        onFirst={searchNav.onFirst}
        onPrev={searchNav.onPrev}
        onNext={searchNav.onNext}
        onEnd={searchNav.onEnd}
        testIdPrefix={tid('search')}
      />
    );
  }, [hasNav, searchNav, testIdPrefix]);

  const renderExpandToolbarButton = useCallback(() => {
    const iconOnly = hasNav;
    return (
      <button
        type="button"
        className={[
          styles.toolbarToggleBtn,
          iconOnly ? styles.toolbarToggleBtnIconOnly : '',
        ].filter(Boolean).join(' ')}
        data-testid={tid('expand')}
        onClick={() => setMobileToolbarExpanded(true)}
        title={iconOnly ? 'Thao tác' : 'Hiển thị thêm thao tác'}
        aria-label="Thao tác"
      >
        <i className="fas fa-chevron-down" aria-hidden />
        {!iconOnly && ' Thao tác'}
      </button>
    );
  }, [hasNav, testIdPrefix]);

  const renderCollapseToolbarButton = useCallback(() => (
    <button
      type="button"
      className={styles.toolbarToggleBtn}
      data-testid={tid('collapse')}
      onClick={() => setMobileToolbarExpanded(false)}
      title="Thu gọn thanh công cụ"
    >
      <i className="fas fa-chevron-up" aria-hidden /> Thu gọn
    </button>
  ), [testIdPrefix]);

  const renderBackButton = useCallback(() => (
    <button
      type="button"
      className={styles.toolbarBtn}
      data-testid={tid('back')}
      onClick={onBack}
    >
      <i className="fas fa-arrow-left" aria-hidden /> Quay lại
    </button>
  ), [onBack, testIdPrefix]);

  const commonViewItems = useMemo((): ToolbarOverflowItem[] => {
    const items: ToolbarOverflowItem[] = [{ key: 'back', node: renderBackButton() }];

    if (showApproveButton) {
      items.push({
        key: 'approve',
        node: (
          <button
            type="button"
            className={styles.toolbarBtn}
            data-testid={tid('approve')}
            onClick={onApprove}
            disabled={!canApprove}
            title={toolbarButtonTitle(
              !!canApprove,
              'Phê duyệt — cập nhật mức xử lý',
              disabledReasons?.approve,
            )}
          >
            <i className="fas fa-check-double" aria-hidden /> Phê duyệt
          </button>
        ),
      });
    }

    if (showPostButton) {
      items.push({
        key: 'post',
        node: (
          <button
            type="button"
            className={styles.toolbarBtn}
            data-testid={tid('post')}
            onClick={onPost}
            disabled={!canPost || posting}
            title={toolbarButtonTitle(
              !!(canPost && !posting),
              'Ghi sổ chứng từ',
              disabledReasons?.post,
            )}
          >
            <i className={`fas ${posting ? 'fa-spinner fa-spin' : 'fa-book'}`} aria-hidden /> Ghi sổ
          </button>
        ),
      });
    }

    if (canViewLedger) {
      items.push({
        key: 'view-ledger',
        node: (
          <button
            type="button"
            className={styles.toolbarBtn}
            data-testid={tid('view-ledger')}
            onClick={onViewLedger}
            title="Xem dữ liệu đã ghi lên sổ cái"
          >
            <i className="fas fa-table-list" aria-hidden /> Xem sổ cái
          </button>
        ),
      });
    }

    if (canViewLinkedVoucher && onViewLinkedVoucher) {
      items.push({
        key: 'view-linked-voucher',
        node: (
          <button
            type="button"
            className={styles.toolbarBtn}
            data-testid={tid('view-linked-voucher')}
            onClick={onViewLinkedVoucher}
            title={viewLinkedVoucherLabel}
          >
            <i className="fas fa-link" aria-hidden /> {viewLinkedVoucherLabel}
          </button>
        ),
      });
    }

    items.push(
      {
        key: 'copy',
        node: (
          <button
            type="button"
            className={styles.toolbarBtn}
            data-testid={tid('copy')}
            onClick={onCopy}
            disabled={!canCopy}
            title={toolbarButtonTitle(!!canCopy, 'Sao chép chứng từ', disabledReasons?.copy)}
          >
            <i className="fas fa-copy" aria-hidden /> Copy
          </button>
        ),
      },
      {
        key: 'print',
        node: (
          <button
            type="button"
            className={styles.toolbarBtn}
            data-testid={tid('print')}
            onClick={onPrint}
            disabled={!canPrint}
            title={toolbarButtonTitle(!!canPrint, 'In chứng từ', disabledReasons?.print)}
          >
            <i className="fas fa-print" aria-hidden /> In
          </button>
        ),
      },
    );

    if (onHistory) {
      items.push({
        key: 'history',
        node: (
          <button
            type="button"
            className={styles.toolbarBtn}
            data-testid={tid('history')}
            onClick={onHistory}
            disabled={!canHistory}
            title={toolbarButtonTitle(
              !!canHistory,
              'Lịch sử thao tác và thay đổi',
              disabledReasons?.history,
            )}
          >
            <i className="fas fa-history" aria-hidden /> Lịch sử
          </button>
        ),
      });
    }

    items.push({
      key: 'search',
      node: (
        <button
          type="button"
          className={styles.toolbarBtn}
          data-testid={tid('search')}
          onClick={onSearch}
          title="Tìm kiếm chứng từ"
        >
          <i className="fas fa-search" aria-hidden /> Tìm kiếm
        </button>
      ),
    });

    return items;
  }, [
    renderBackButton,
    showApproveButton,
    showPostButton,
    canViewLedger,
    onHistory,
    canApprove,
    canPost,
    posting,
    canCopy,
    canPrint,
    canHistory,
    disabledReasons,
    onApprove,
    onPost,
    onViewLedger,
    onCopy,
    onPrint,
    onSearch,
    testIdPrefix,
  ]);

  const line1TrailingPrimaryKeys = useMemo((): string[] => {
    if (showApproveButton) return ['approve'];
    if (canViewLedger) return ['view-ledger'];
    return [];
  }, [showApproveButton, canViewLedger]);

  const detailViewItems = useMemo((): ToolbarOverflowItem[] => {
    const items: ToolbarOverflowItem[] = [];

    if (showNewButton) {
      items.push({
        key: 'new',
        node: (
          <button
            type="button"
            className={styles.toolbarBtn}
            data-testid={tid('new')}
            onClick={onNew}
            title="Tạo chứng từ mới"
          >
            <i className="fas fa-plus" aria-hidden /> Tạo mới
          </button>
        ),
      });
    }

    if (showEditButton) {
      items.push({
        key: 'edit',
        node: (
          <button
            type="button"
            className={styles.toolbarBtn}
            data-testid={tid('edit')}
            onClick={onEdit}
            disabled={!canEdit}
            title={toolbarButtonTitle(!!canEdit, 'Sửa chứng từ', disabledReasons?.edit)}
          >
            <i className="fas fa-edit" aria-hidden /> Sửa
          </button>
        ),
      });
    }

    if (showDeleteButton) {
      items.push({
        key: 'delete',
        node: (
          <button
            type="button"
            className={styles.toolbarBtnDanger}
            data-testid={tid('delete')}
            onClick={onDelete}
            disabled={!canDelete}
            title={toolbarButtonTitle(!!canDelete, 'Xóa chứng từ', disabledReasons?.delete)}
          >
            <i className="fas fa-trash-alt" aria-hidden /> Xóa
          </button>
        ),
      });
    }

    return items;
  }, [
    showEditButton,
    showDeleteButton,
    showNewButton,
    canEdit,
    canDelete,
    disabledReasons,
    onNew,
    onEdit,
    onDelete,
    testIdPrefix,
  ]);

  const editDetailItems = useMemo((): ToolbarOverflowItem[] => [
    {
      key: 'cancel',
      node: (
        <button
          type="button"
          className={styles.toolbarBtn}
          data-testid={tid('cancel')}
          onClick={onCancel}
          disabled={saving}
          title="Hủy thay đổi"
        >
          <i className="fas fa-times" aria-hidden /> Hủy
        </button>
      ),
    },
    {
      key: 'save',
      node: (
        <button
          type="button"
          className={styles.toolbarBtnPrimary}
          data-testid={tid('save')}
          onClick={onSave}
          disabled={saving || !canSave}
          title={toolbarButtonTitle(!!canSave && !saving, 'Lưu chứng từ', disabledReasons?.save)}
        >
          <i className={`fas ${saving ? 'fa-spinner fa-spin' : 'fa-save'}`} aria-hidden /> {saveLabel}
        </button>
      ),
    },
  ], [saving, canSave, saveLabel, disabledReasons, onCancel, onSave, testIdPrefix]);

  const commonWithoutBack = useMemo(
    () => commonViewItems.filter((item) => item.key !== 'back'),
    [commonViewItems],
  );

  const line1ItemsForMobile = useMemo(() => {
    if (useCompactToolbar) return commonWithoutBack;
    return commonViewItems;
  }, [useCompactToolbar, commonWithoutBack, commonViewItems]);

  const line1PinnedKeys = useMemo((): string[] => {
    if (useCompactToolbar) return [];
    return ['back'];
  }, [useCompactToolbar]);

  const narrowStackClass = hasNav ? styles.toolbarStackThreeRows : styles.toolbarStackTwoRows;
  const toolbarStackLayoutClass =
    isEditing || showMobileCollapsed || !showMobileExpanded
      ? styles.toolbarStackSingle
      : narrowStackClass;

  const titleBlockEl = (
    <div
      className={[
        styles.titleBlock,
        insetShell ? styles.titleBlockInset : '',
      ].filter(Boolean).join(' ')}
    >
      <div className={styles.titleRow}>
        <h1 className={styles.title} data-testid={tid('title')}>{title}</h1>
        {processingLevelBadge}
      </div>
      {viewModeHint && formMode === FormMode.View && (
        viewModeHint.kind === 'editable' ? (
          <div className={styles.viewModeHint} data-testid={tid('view-hint')}>
            <i className="fas fa-eye" aria-hidden /> Chế độ xem — nhấn <strong>Sửa</strong> để chỉnh sửa
          </div>
        ) : (
          <div className={styles.readOnlyHint} data-testid={tid('view-locked-hint')}>
            <i className="fas fa-lock" aria-hidden /> {viewModeHint.message}
          </div>
        )
      )}
      {isEditing && copySourceVoucherCode?.trim() && formMode === FormMode.Create && (
        <div className={styles.readOnlyHint} data-testid={tid('copy-hint')}>
          <i className="fas fa-copy" aria-hidden /> Bạn đang thực hiện copy từ <strong>{copySourceVoucherCode.trim()}</strong>
        </div>
      )}
      {isEditing && !(copySourceVoucherCode?.trim() && formMode === FormMode.Create) && (
        <div className={styles.readOnlyHint} data-testid={tid('edit-hint')}>
          <i className="fas fa-pen" aria-hidden /> Đang {formMode === FormMode.Create ? 'tạo mới' : 'chỉnh sửa'} — Lưu hoặc Hủy
        </div>
      )}
    </div>
  );

  return (
    <>
      {useCompactToolbar ? (
        <>
          <div
            className={[
              styles.toolbarStack,
              toolbarStackLayoutClass,
              insetShell ? styles.toolbarInsetStack : '',
            ].filter(Boolean).join(' ')}
            data-testid={tid('bar')}
          >
            {showMobileCollapsed ? (
              <div className={styles.toolbarRowCollapsed} data-testid={tid('collapsed-row')}>
                {renderBackButton()}
                {hasNav && (
                  <div className={styles.toolbarCollapsedNav}>
                    {renderSearchNav()}
                  </div>
                )}
                <div className={styles.toolbarCollapsedToggle}>
                  {renderExpandToolbarButton()}
                </div>
              </div>
            ) : (
              <>
                <div className={styles.toolbarRowExpandToggle}>
                  {renderBackButton()}
                  <div className={styles.toolbarCollapsedToggle}>
                    {renderCollapseToolbarButton()}
                  </div>
                </div>
                <ToolbarResponsiveRow
                  rowTestId={tid('left')}
                  rowClassName={styles.toolbarRowLine1}
                  testIdPrefix={testIdPrefix}
                  items={line1ItemsForMobile}
                  maxVisible={line1ItemsForMobile.length}
                  layout="common"
                  pinnedKeys={line1PinnedKeys}
                  trailingPrimaryKeys={line1TrailingPrimaryKeys}
                  narrow={viewMobile}
                />
                <ToolbarResponsiveRow
                  rowTestId={tid('right')}
                  testIdPrefix={testIdPrefix}
                  items={detailViewItems}
                  maxVisible={DETAIL_ACTIONS_MAX_VISIBLE}
                  layout="detail"
                />
                {hasNav && (
                  <div className={styles.toolbarRowNav} data-testid={tid('search-nav-row')}>
                    {renderSearchNav()}
                  </div>
                )}
              </>
            )}
          </div>
          {titleBlockEl}
        </>
      ) : (
        <>
          {!showMobileCollapsed && (
            <div
              className={[
                styles.toolbarStack,
                toolbarStackLayoutClass,
                insetShell ? styles.toolbarInsetStack : '',
              ].filter(Boolean).join(' ')}
              data-testid={tid('bar')}
            >
              {isEditing ? (
                <ToolbarResponsiveRow
                  rowTestId={tid('edit-bar')}
                  testIdPrefix={testIdPrefix}
                  layout="edit"
                  pinnedKeys={['back']}
                  items={[
                    { key: 'back', node: renderBackButton() },
                    ...editDetailItems,
                  ]}
                  maxVisible={DETAIL_ACTIONS_MAX_VISIBLE}
                />
              ) : !viewMobile ? (
                <div className={styles.toolbarRowSingle} data-testid={tid('single-row')}>
                  {renderBackButton()}
                  <div className={styles.toolbarCommonCluster} data-testid={tid('left')}>
                    {commonWithoutBack.map((item) => (
                      <React.Fragment key={item.key}>{item.node}</React.Fragment>
                    ))}
                  </div>
                  <div className={styles.toolbarRightCluster} data-testid={tid('right')}>
                    {renderSearchNav()}
                    {detailViewItems.map((item) => (
                      <React.Fragment key={item.key}>{item.node}</React.Fragment>
                    ))}
                  </div>
                </div>
              ) : (
                <>
                  <ToolbarResponsiveRow
                    rowTestId={tid('left')}
                    rowClassName={styles.toolbarRowLine1}
                    testIdPrefix={testIdPrefix}
                    items={line1ItemsForMobile}
                    maxVisible={line1ItemsForMobile.length}
                    layout="common"
                    pinnedKeys={line1PinnedKeys}
                    trailingPrimaryKeys={line1TrailingPrimaryKeys}
                    narrow={viewMobile}
                  />
                  <ToolbarResponsiveRow
                    rowTestId={tid('right')}
                    testIdPrefix={testIdPrefix}
                    items={detailViewItems}
                    maxVisible={DETAIL_ACTIONS_MAX_VISIBLE}
                    layout="detail"
                  />
                  {hasNav && (
                    <div className={styles.toolbarRowNav} data-testid={tid('search-nav-row')}>
                      {renderSearchNav()}
                    </div>
                  )}
                </>
              )}
            </div>
          )}
          {titleBlockEl}
        </>
      )}
    </>
  );
};
