import React, { useMemo } from 'react';
import styles from './VoucherFormToolbar.module.css';
import { ToolbarOverflowMenu, type ToolbarOverflowItem } from './ToolbarOverflowMenu';

export type ToolbarRowLayout = 'common' | 'detail' | 'edit';

export interface ToolbarResponsiveRowProps {
  rowTestId: string;
  testIdPrefix: string;
  items: ToolbarOverflowItem[];
  /** Max buttons visible before overflow (detail row; ignored when common + narrow). */
  maxVisible: number;
  /** Optional row class (e.g. line-1 border in two-row stack). */
  rowClassName?: string;
  /** `common` Line 1 · `detail` Line 2 · `edit` Create/Edit 1 hàng (Quay lại trái · Hủy/Lưu phải). */
  layout?: ToolbarRowLayout;
  /** Keys pinned left — never in dropdown (Line 1: `back`). */
  pinnedKeys?: string[];
  /** Keys visible after ⋯ when narrow (Line 1: `approve` / `view-ledger`). */
  trailingPrimaryKeys?: string[];
  narrow?: boolean;
}

function splitCommonRow(
  items: ToolbarOverflowItem[],
  pinnedKeys: string[],
  trailingPrimaryKeys: string[],
  narrow: boolean,
): { pinned: ToolbarOverflowItem[]; trailing: ToolbarOverflowItem[]; overflow: ToolbarOverflowItem[] } {
  const pinnedSet = new Set(pinnedKeys);
  const trailingSet = new Set(trailingPrimaryKeys);

  const pinned = pinnedKeys
    .map((key) => items.find((item) => item.key === key))
    .filter((item): item is ToolbarOverflowItem => !!item);

  if (!narrow) {
    return { pinned: [], trailing: items, overflow: [] };
  }

  const trailing = trailingPrimaryKeys
    .map((key) => items.find((item) => item.key === key))
    .filter((item): item is ToolbarOverflowItem => !!item);

  const overflow = items.filter((item) => !pinnedSet.has(item.key) && !trailingSet.has(item.key));

  return { pinned, trailing, overflow };
}

function splitDetailRow(
  items: ToolbarOverflowItem[],
  maxVisible: number,
): { visible: ToolbarOverflowItem[]; overflow: ToolbarOverflowItem[] } {
  if (items.length <= maxVisible) {
    return { visible: items, overflow: [] };
  }
  return {
    visible: items.slice(0, maxVisible),
    overflow: items.slice(maxVisible),
  };
}

export const ToolbarResponsiveRow: React.FC<ToolbarResponsiveRowProps> = ({
  rowTestId,
  testIdPrefix,
  items,
  maxVisible,
  rowClassName,
  layout = 'detail',
  pinnedKeys = [],
  trailingPrimaryKeys = [],
  narrow = false,
}) => {
  const commonSplit = useMemo(
    () => (layout === 'common' ? splitCommonRow(items, pinnedKeys, trailingPrimaryKeys, narrow) : null),
    [layout, items, pinnedKeys, trailingPrimaryKeys, narrow],
  );

  const detailSplit = useMemo(
    () => (layout === 'detail' ? splitDetailRow(items, maxVisible) : null),
    [layout, items, maxVisible],
  );

  if (layout === 'edit') {
    const pinnedSet = new Set(pinnedKeys);
    const pinned = pinnedKeys
      .map((key) => items.find((item) => item.key === key))
      .filter((item): item is ToolbarOverflowItem => !!item);
    const trailing = items.filter((item) => !pinnedSet.has(item.key));

    return (
      <div
        className={[
          styles.toolbarRow,
          styles.toolbarRowSplit,
          rowClassName,
        ].filter(Boolean).join(' ')}
        data-testid={rowTestId}
      >
        <div className={styles.toolbarPinnedCluster} data-testid={`${testIdPrefix}-toolbar-left`}>
          {pinned.map((item) => (
            <React.Fragment key={item.key}>{item.node}</React.Fragment>
          ))}
        </div>
        <div className={styles.toolbarRightCluster} data-testid={`${testIdPrefix}-toolbar-right`}>
          {trailing.map((item) => (
            <React.Fragment key={item.key}>{item.node}</React.Fragment>
          ))}
        </div>
      </div>
    );
  }

  if (layout === 'common' && commonSplit) {
    const { pinned, trailing, overflow } = commonSplit;
    const hasOverflow = overflow.length > 0;

    if (narrow && hasOverflow) {
      return (
        <div
          className={[styles.toolbarRow, styles.toolbarRowCommon, styles.toolbarRowSplit].join(' ')}
          data-testid={rowTestId}
        >
          {pinned.map((item) => (
            <React.Fragment key={item.key}>{item.node}</React.Fragment>
          ))}
          <div className={styles.toolbarRightCluster}>
            <ToolbarOverflowMenu testIdPrefix={testIdPrefix} items={overflow} />
            {trailing.map((item) => (
              <React.Fragment key={item.key}>{item.node}</React.Fragment>
            ))}
          </div>
        </div>
      );
    }

    const inline = hasOverflow ? [] : items;
    if (!hasOverflow) {
      return (
        <div className={[styles.toolbarRow, styles.toolbarRowCommon].join(' ')} data-testid={rowTestId}>
          {inline.map((item) => (
            <React.Fragment key={item.key}>{item.node}</React.Fragment>
          ))}
        </div>
      );
    }
  }

  const { visible = [], overflow = [] } = detailSplit ?? { visible: items, overflow: [] };
  const hasOverflow = overflow.length > 0;

  if (visible.length === 0 && !hasOverflow) return null;

  return (
    <div
      className={[styles.toolbarRow, styles.toolbarRowDetail].filter(Boolean).join(' ')}
      data-testid={rowTestId}
    >
      <div className={styles.toolbarRightCluster}>
        {hasOverflow && <ToolbarOverflowMenu testIdPrefix={testIdPrefix} items={overflow} />}
        {visible.map((item) => (
          <React.Fragment key={item.key}>{item.node}</React.Fragment>
        ))}
      </div>
    </div>
  );
};
