import type { DocumentPostingStatus } from '../services/kt/models';
import { canShowVoucherEditDelete } from './voucherToolbarActions';

/** List row fields shared by cash vouchers, journal entries, … */
export type VoucherListRowActionsInput = {
  status: string;
  processingLevel: string;
};

/**
 * Form toolbar — `voucher-form-toolbar.md` § Ledger view:
 * `status === 'Posted'` hoặc `postingStatus !== 'None'` (đang/đã ghi sổ).
 * Cấm chỉ dựa mức 9 khi chưa enqueue post.
 */
export function canViewVoucherLedgerFromForm(input: {
  isNew: boolean;
  id?: string | null;
  status: string;
  processingLevel?: string;
  postingStatus: DocumentPostingStatus | string;
  canViewLedgerPermission: boolean;
}): boolean {
  if (input.isNew || !input.id || !input.canViewLedgerPermission) return false;
  if (input.status === 'Posted') return true;
  if (input.processingLevel === '9') return true;
  const ps = input.postingStatus as DocumentPostingStatus;
  if (ps === 'Queued' || ps === 'Processing') return true;
  if (ps === 'Failed') return true;
  return false;
}

/**
 * List toolbar / row menu — Posted (đã có GL) hoặc mức 9 (Hoạch toán: chờ/đang job).
 * Modal `VoucherPostedLedgerModal` hiển thị Queued/Processing khi chưa có dòng sổ.
 */
export function canViewLedgerFromListRow(
  row: VoucherListRowActionsInput,
  canViewLedgerPermission: boolean,
): boolean {
  if (!canViewLedgerPermission) return false;
  if (row.status === 'Posted') return true;
  return row.processingLevel === '9';
}

export function canEditFromListRow(
  row: VoucherListRowActionsInput,
  canUpdatePermission: boolean,
): boolean {
  return canUpdatePermission && canShowVoucherEditDelete(row.status, row.processingLevel, false);
}
